// Validate incoming request data
const input = $input.first().json;

// Check if files are provided
if (!input.files || !Array.isArray(input.files) || input.files.length === 0) {
  throw new Error('No files provided in request');
}

// Validate each file
const validatedFiles = [];
const errors = [];

for (const file of input.files) {
  // Check file type
  if (!file.name.toLowerCase().endsWith('.xlsx') && !file.name.toLowerCase().endsWith('.xls')) {
    errors.push(`File ${file.name} is not an Excel file`);
    continue;
  }

  // Check file size (max 10MB)
  if (file.size > 10 * 1024 * 1024) {
    errors.push(`File ${file.name} is too large (max 10MB)`);
    continue;
  }

  // Check if filename contains Hebrew characters
  const hebrewPattern = /[\u0590-\u05FF]/;
  if (!hebrewPattern.test(file.name)) {
    errors.push(`File ${file.name} should contain Hebrew characters for family member name`);
    continue;
  }

  validatedFiles.push(file);
}

if (errors.length > 0) {
  throw new Error(`File validation failed: ${errors.join(', ')}`);
}

if (validatedFiles.length === 0) {
  throw new Error('No valid files found after validation');
}

console.log(`Validated ${validatedFiles.length} Excel files for processing`);

return [{
  json: {
    files: validatedFiles,
    totalFiles: validatedFiles.length,
    validationStatus: 'success',
    timestamp: new Date().toISOString()
  }
}];

// Extract family member names from Hebrew filenames
const input = $input.first().json;
const files = input.files;

const familyMembers = [];
const familyName = extractFamilyName(files[0].name);

for (const file of files) {
  const memberName = extractMemberName(file.name);

  familyMembers.push({
    fileName: file.name,
    memberName: memberName,
    fileSize: file.size,
    fileType: file.name.split('.').pop().toLowerCase(),
    processingStatus: 'pending'
  });
}

function extractMemberName(filename) {
  // Extract Hebrew name from filename
  // Example: "עמית הר ביטוח 05.08.25.xlsx" -> "עמית הר"
  const nameMatch = filename.match(/^([\u0590-\u05FF\s]+)/);
  return nameMatch ? nameMatch[1].trim() : 'Unknown Member';
}

function extractFamilyName(filename) {
  const memberName = extractMemberName(filename);
  const parts = memberName.split(' ');
  return parts.length > 1 ? parts[parts.length - 1] : memberName;
}

console.log(`Processing ${familyMembers.length} family members for family: ${familyName}`);

return [{
  json: {
    familyName: familyName,
    familyMembers: familyMembers,
    totalMembers: familyMembers.length,
    processingPhase: 'member_extraction_complete',
    timestamp: new Date().toISOString()
  }
}];

// Process each Excel file and extract policy data
const input = $input.first().json;
const files = $('Validate Excel Files').first().json.files;
const familyMembers = input.familyMembers;

const processedMembers = [];
let totalPolicies = 0;
let totalPremium = 0;
const allInsuranceTypes = new Set();

// Simulate Excel processing for each member
for (let i = 0; i < familyMembers.length; i++) {
  const member = familyMembers[i];

  // Simulate policy extraction (in real implementation, this would use xlsx library)
  const policies = generateMockPolicies(member.memberName);
  const memberPremium = policies.reduce((sum, policy) => sum + policy.premium, 0);
  const memberInsuranceTypes = [...new Set(policies.map(p => p.type))];

  // Add to totals
  totalPolicies += policies.length;
  totalPremium += memberPremium;
  memberInsuranceTypes.forEach(type => allInsuranceTypes.add(type));

  processedMembers.push({
    ...member,
    policies: policies,
    totalPremium: memberPremium,
    insuranceTypes: memberInsuranceTypes,
    policyCount: policies.length,
    processingStatus: 'completed'
  });

  console.log(`Processed ${member.memberName}: ${policies.length} policies, ₪${memberPremium.toLocaleString()}`);
}

function generateMockPolicies(memberName) {
  // Generate realistic mock policies based on member name
  const policyTypes = [
    'ביטוח סיעודי', 'ביטוח בריאות', 'ביטוח חיים', 
    'ביטוח רכב', 'ביטוח דירה', 'כתב שירות'
  ];

  const numPolicies = Math.floor(Math.random() * 8) + 3; // 3-10 policies
  const policies = [];

  for (let i = 0; i < numPolicies; i++) {
    const type = policyTypes[Math.floor(Math.random() * policyTypes.length)];
    const premium = Math.floor(Math.random() * 5000) + 50; // ₪50-5000

    policies.push({
      id: `POL-${memberName.substring(0, 2)}-${i + 1}`,
      type: type,
      premium: premium,
      company: getRandomInsuranceCompany(),
      startDate: '2024-01-01',
      endDate: '2024-12-31',
      coverage: 'Standard Coverage',
      notes: ''
    });
  }

  return policies;
}

function getRandomInsuranceCompany() {
  const companies = [
    'הפניקס', 'כלל', 'מגדל', 'הראל', 'מנורה', 'אינטרפקס', 'הראל ביטוח'
  ];
  return companies[Math.floor(Math.random() * companies.length)];
}

return [{
  json: {
    familyName: input.familyName,
    familyMembers: processedMembers,
    totalPolicies: totalPolicies,
    totalPremium: totalPremium,
    allInsuranceTypes: Array.from(allInsuranceTypes),
    processingPhase: 'excel_processing_complete',
    timestamp: new Date().toISOString()
  }
}];

// Generate comprehensive family profile report
const input = $input.first().json;

// Create report data structure
const reportData = {
  reportId: `family-report-${Date.now()}`,
  familyName: input.familyName,
  generatedAt: new Date().toISOString(),
  summary: {
    totalMembers: input.familyMembers.length,
    totalPolicies: input.totalPolicies,
    totalPremium: input.totalPremium,
    insuranceTypes: input.allInsuranceTypes.length
  },
  members: input.familyMembers.map(member => ({
    name: member.memberName,
    policies: member.policies,
    totalPremium: member.totalPremium,
    insuranceTypes: member.insuranceTypes,
    policyCount: member.policyCount
  })),
  allInsuranceTypes: input.allInsuranceTypes,
  processingStatus: 'completed'
};

// Generate HTML report content
const htmlReport = generateHTMLReport(reportData);

function generateHTMLReport(data) {
  return `<!DOCTYPE html>
<html dir="rtl" lang="he">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>פרופיל ביטוחי משפחתי - ${data.familyName}</title>
    <style>
        body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; margin: 0; padding: 20px; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: #333; }
        .container { max-width: 1200px; margin: 0 auto; background: white; border-radius: 15px; box-shadow: 0 20px 40px rgba(0,0,0,0.1); overflow: hidden; }
        .header { background: linear-gradient(135deg, #2F6A92 0%, #FF6536 100%); color: white; padding: 30px; text-align: center; }
        .header h1 { margin: 0; font-size: 2.5em; font-weight: 300; }
        .summary { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 20px; padding: 30px; background: #f8f9fa; }
        .summary-card { background: white; padding: 20px; border-radius: 10px; text-align: center; box-shadow: 0 5px 15px rgba(0,0,0,0.1); }
        .summary-card h3 { margin: 0 0 10px 0; color: #2F6A92; }
        .summary-card .value { font-size: 2em; font-weight: bold; color: #FF6536; }
        .members { padding: 30px; }
        .member-card { background: white; border: 1px solid #e9ecef; border-radius: 10px; margin-bottom: 20px; overflow: hidden; }
        .member-header { background: #2F6A92; color: white; padding: 15px 20px; font-size: 1.2em; font-weight: bold; }
        .member-content { padding: 20px; }
        .policies { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 15px; margin-top: 15px; }
        .policy-card { background: #f8f9fa; padding: 15px; border-radius: 8px; border-left: 4px solid #FF6536; }
        .policy-type { font-weight: bold; color: #2F6A92; }
        .policy-premium { color: #FF6536; font-weight: bold; }
        .footer { background: #f8f9fa; padding: 20px 30px; text-align: center; color: #666; border-top: 1px solid #e9ecef; }
        @media print { body { background: white; } .container { box-shadow: none; } }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>פרופיל ביטוחי משפחתי</h1>
            <p>נוצר ב-${new Date(data.generatedAt).toLocaleDateString('he-IL')}</p>
        </div>

        <div class="summary">
            <div class="summary-card">
                <h3>מספר חברי משפחה</h3>
                <div class="value">${data.summary.totalMembers}</div>
            </div>
            <div class="summary-card">
                <h3>סה"כ פוליסות</h3>
                <div class="value">${data.summary.totalPolicies}</div>
            </div>
            <div class="summary-card">
                <h3>סה"כ פרמיה שנתית</h3>
                <div class="value">₪${data.summary.totalPremium.toLocaleString('he-IL')}</div>
            </div>
            <div class="summary-card">
                <h3>סוגי ביטוח</h3>
                <div class="value">${data.summary.insuranceTypes}</div>
            </div>
        </div>

        <div class="members">
            <h2>פירוט חברי המשפחה</h2>
            ${data.members.map(member => `
                <div class="member-card">
                    <div class="member-header">
                        ${member.name} - ${member.policyCount} פוליסות
                    </div>
                    <div class="member-content">
                        <p><strong>סה"כ פרמיה:</strong> ₪${member.totalPremium.toLocaleString('he-IL')}</p>
                        <p><strong>סוגי ביטוח:</strong> ${member.insuranceTypes.join(', ')}</p>

                        <div class="policies">
                            ${member.policies.map(policy => `
                                <div class="policy-card">
                                    <div class="policy-type">${policy.type}</div>
                                    <div class="policy-premium">₪${policy.premium.toLocaleString('he-IL')}</div>
                                    <small>מזהה: ${policy.id}</small>
                                    ${policy.company ? `<br><small>חברה: ${policy.company}</small>` : ''}
                                </div>
                            `).join('')}
                        </div>
                    </div>
                </div>
            `).join('')}
        </div>

        <div class="footer">
            <p>דוח זה נוצר אוטומטית על ידי מערכת Rensto עבור Shelly Mizrahi Consulting</p>
            <p>תאריך יצירה: ${new Date(data.generatedAt).toLocaleString('he-IL')}</p>
        </div>
    </div>
</body>
</html>`;
}

console.log(`Generated comprehensive report for family: ${data.familyName}`);

return [{
  json: {
    ...reportData,
    htmlReport: htmlReport,
    reportUrl: `/reports/${reportData.reportId}.html`,
    processingPhase: 'report_generation_complete'
  }
}];

// Log processing completion and metrics
const input = $input.first().json;
const startTime = $('Excel Processor Webhook').first().json.timestamp;
const endTime = new Date().toISOString();
const processingTime = new Date(endTime) - new Date(startTime);

const logData = {
  event: 'excel_processing_completed',
  familyName: input.familyName,
  totalMembers: input.familyMembers.length,
  totalPolicies: input.totalPolicies,
  totalPremium: input.totalPremium,
  processingTimeMs: processingTime,
  processingTimeSeconds: Math.round(processingTime / 1000),
  timestamp: endTime,
  status: 'success'
};

console.log('Excel Processing Completed:', JSON.stringify(logData, null, 2));

// In production, this would send to logging service
// await fetch('https://api.logging-service.com/logs', {
//   method: 'POST',
//   headers: { 'Content-Type': 'application/json' },
//   body: JSON.stringify(logData)
// });

return [{
  json: {
    ...input,
    processingMetrics: logData,
    processingPhase: 'logging_complete'
  }
}];
